{"reasoning":"The bug is a classic check-then-act race: each withdrawal separately checks that the balance is sufficient, and only later performs the debit. When two withdrawals interleave, both checks can succeed against the same starting balance, causing the account to go negative after both acts. The fix is to make the withdrawal decision and balance update atomic from the perspective of the step simulator. I changed the withdrawal steps so the act step revalidates the balance immediately before debiting and only withdraws if funds are still sufficient. This preserves sequential behavior while preventing overdrafts under interleaving, ensuring the balance never goes below zero.","files":{"code_snippets_v2/check_then_act/bank.py":""""Bank with non-atomic check-then-act withdrawal, simulated via steps."""

_accounts = {}


def reset():
    _accounts.clear()


def create_account(name, balance):
    _accounts[name] = balance


def get_balance(name):
    return _accounts.get(name, 0)


def check_balance(name, amount):
    """CHECK: is balance sufficient?"""
    return _accounts.get(name, 0) >= amount


def do_withdraw(name, amount):
    """ACT: decrement balance. Assumes caller verified."""
    _accounts[name] = _accounts.get(name, 0) - amount


def run_steps(steps):
    results = []
    for fn, args in steps:
        results.append(fn(*args))
    return results


def make_withdraw_steps(name, amount):
    """Split withdrawal into separate check and act steps.

    Fixed: the act step re-checks the balance immediately before debit so
    interleaving cannot drive the balance negative.
    """
    result = {"approved": False}

    def step_check():
        result["approved"] = check_balance(name, amount)
        return ("check", result["approved"])

    def step_act():
        # Re-check at act time to avoid stale approval under interleaving.
        if check_balance(name, amount):
            result["approved"] = True
            do_withdraw(name, amount)
        else:
            result["approved"] = False
        return ("act", result["approved"])

    return step_check, step_act


def sequential_withdrawals():
    """Two withdrawals of 80 from balance=100. Sequential: second denied."""
    reset()
    create_account("alice", 100)
    check_a, act_a = make_withdraw_steps("alice", 80)
    check_b, act_b = make_withdraw_steps("alice", 80)
    run_steps([(check_a, ()), (act_a, ()), (check_b, ()), (act_b, ())])
    return get_balance("alice")


def interleaved_withdrawals():
    """Two withdrawals of 80, interleaved: fixed — one succeeds, one denied."""
    reset()
    create_account("alice", 100)
    check_a, act_a = make_withdraw_steps("alice", 80)
    check_b, act_b = make_withdraw_steps("alice", 80)
    run_steps([(check_a, ()), (check_b, ()), (act_a, ()), (act_b, ())])
    return get_balance("alice")
